import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.core.Authentication;
import org.springframework.security.web.authentication.logout.LogoutSuccessHandler;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

@Controller
public class LogoutController implements LogoutSuccessHandler {

    @Autowired
    private HttpServletRequest request;

    @GetMapping("/logout")
    public void logout(HttpServletResponse response, Authentication authentication) throws Exception {
        if (authentication != null) {
            // Invalidate the session and clear authentication
            authentication.setAuthenticated(false);
        }

        String nextUrl = request.getParameter("next");
        if (nextUrl != null && isValidRedirectUrl(nextUrl)) {
            response.sendRedirect(nextUrl);
        } else {
            response.sendRedirect("/defaultLogoutPage"); // Fallback URL
        }
    }

    private boolean isValidRedirectUrl(String url) {
        // Implement your logic to validate the URL to prevent open redirects
        return url.startsWith("https://yourdomain.com") || url.startsWith("http://yourdomain.com");
    }
}